// ── VAPI end-of-call-report payload mapping ──────────────────────────────
// VAPI sends: { message: { type, call, transcript, summary, recordingUrl,
//   stereoRecordingUrl, durationSeconds, analysis: { summary, structuredData,
//   successEvaluation } } }

const body = $input.first().json.body ?? $input.first().json;

// Only process end-of-call-report events; ignore status-update pings etc.
const msgType = body?.message?.type ?? body?.type ?? '';
if (msgType !== 'end-of-call-report') {
  return [{ json: { __skip: true, type: msgType } }];
}

const msg  = body.message ?? body;
const call = msg.call ?? {};
const analysis = msg.analysis ?? {};
const customer = call.customer ?? {};
const assistant = call.assistant ?? {};

// ── Auto-generate Row ID ──────────────────────────────────────────────────
// Format: CALL-<epoch-ms>-<4-char hex>  e.g. CALL-1742601234567-A3F1
const now   = new Date();
const rowId = 'CALL-' + now.getTime() + '-' +
  Math.floor(Math.random() * 0xFFFF).toString(16).toUpperCase().padStart(4, '0');

// ── Timestamps ───────────────────────────────────────────────────────────
// Logged-at = moment this webhook was received (always present)
const loggedAt = now.toISOString();

// Call start/end come from VAPI (ISO strings)
const callStartedAt = call.startedAt ?? call.createdAt ?? loggedAt;
const callEndedAt   = call.endedAt   ?? loggedAt;

// Human-readable date + time from call start
const startDate = new Date(callStartedAt);
const dateFormatted = startDate.toLocaleDateString('en-US', { year:'numeric', month:'2-digit', day:'2-digit' });
const timeFormatted = startDate.toLocaleTimeString('en-US', { hour:'2-digit', minute:'2-digit', second:'2-digit', hour12:false });

// Duration: prefer VAPI's durationSeconds, fall back to computed diff
let durationSec = msg.durationSeconds ?? null;
if (durationSec === null && call.startedAt && call.endedAt) {
  durationSec = Math.round((new Date(call.endedAt) - new Date(call.startedAt)) / 1000);
}
const durationFormatted = durationSec !== null
  ? Math.floor(durationSec / 60) + ':' + String(durationSec % 60).padStart(2, '0')
  : '';

// ── Field extraction ─────────────────────────────────────────────────────
const callerPhone  = customer.number ?? customer.phoneNumber ?? '';
const callerName   = customer.name   ?? '';
const callType     = call.type       ?? '';
const callId       = call.id         ?? '';
const assistantName = assistant.name ?? call.assistantId ?? '';
const transcript   = msg.transcript  ?? '';
const summary      = msg.summary     ?? analysis.summary ?? '';
const recordingUrl = msg.recordingUrl ?? msg.stereoRecordingUrl ?? '';
const successEval  = analysis.successEvaluation ?? '';

// structured data from VAPI analysis (flatten to JSON string if object)
let structuredData = analysis.structuredData ?? '';
if (typeof structuredData === 'object') {
  structuredData = JSON.stringify(structuredData);
}

return [{
  json: {
    row_id:          rowId,
    logged_at:       loggedAt,
    date:            dateFormatted,
    time:            timeFormatted,
    call_id:         callId,
    call_type:       callType,
    caller_phone:    callerPhone,
    caller_name:     callerName,
    assistant_name:  assistantName,
    call_started_at: callStartedAt,
    call_ended_at:   callEndedAt,
    duration:        durationFormatted,
    duration_sec:    durationSec ?? '',
    summary:         summary,
    transcript:      transcript,
    recording_url:   recordingUrl,
    success_eval:    successEval,
    structured_data: structuredData
  }
}];
